// src/pages/CreateCourse.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { coursesService } from '../services/courses';

const CreateCourse = () => {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    price: '',
    image: null,
  });
  const navigate = useNavigate();

  // جب بيانات المستخدم من localStorage
  const user = JSON.parse(localStorage.getItem('user'));
  
  // لو مش مُدرّس → رجعه للرئيسية
  if (!user || !user.is_instructor) {
    alert('فقط المدرّسين يمكنهم إنشاء كورسات');
    navigate('/');
    return null;
  }

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (name === 'image') {
      setFormData({ ...formData, image: files[0] });
    } else {
      setFormData({ ...formData, [name]: value });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    const courseData = {
      title: formData.title,
      description: formData.description,
      price: formData.price,
      // instructor: user.id, // ← هنا السر!
      image: formData.image,
    };

    try {
      console.log("Current token:", localStorage.getItem('token'));
      await coursesService.create(courseData);
      alert('تم إنشاء الكورس بنجاح!');
      navigate('/courses');
    } catch (error) {
      console.error('Error creating course:', error.response?.data);
      alert('فشل إنشاء الكورس: ' + (error.response?.data?.detail || 'حدث خطأ'));
    }
  };

  return (
    <div style={{ padding: '20px', maxWidth: '600px', margin: '0 auto' }}>
      <h2>إنشاء كورس جديد</h2>
      <form onSubmit={handleSubmit}>
        <div style={{ marginBottom: '15px' }}>
          <label>العنوان:</label>
          <input
            type="text"
            name="title"
            value={formData.title}
            onChange={handleChange}
            required
            style={{ width: '100%', padding: '8px' }}
          />
        </div>

        <div style={{ marginBottom: '15px' }}>
          <label>الوصف:</label>
          <textarea
            name="description"
            value={formData.description}
            onChange={handleChange}
            required
            rows="4"
            style={{ width: '100%', padding: '8px' }}
          />
        </div>

        <div style={{ marginBottom: '15px' }}>
          <label>السعر:</label>
          <input
            type="number"
            name="price"
            value={formData.price}
            onChange={handleChange}
            step="0.01"
            min="0"
            required
            style={{ width: '100%', padding: '8px' }}
          />
        </div>

        <div style={{ marginBottom: '15px' }}>
          <label>صورة الكورس:</label>
          <input
            type="file"
            name="image"
            accept="image/*"
            onChange={handleChange}
            style={{ width: '100%' }}
          />
        </div>

        <div style={{ marginBottom: '15px' }}>
          <label>المُدرّس:</label>
          <strong>{user.first_name} {user.last_name}</strong>
        </div>

        <button 
          type="submit" 
          style={{ padding: '10px 20px', backgroundColor: '#007bff', color: 'white', border: 'none', cursor: 'pointer' }}
        >
          إنشاء الكورس
        </button>
      </form>
    </div>
  );
};

export default CreateCourse;
